export class ProcedureManagementComponent {
  constructor() {
    this.procedureManagementService = inject(ProcedureManagementService);
    this.procedures = [];
    this.selectedProcedure = null;
    this.searchTerm = '';
    this.isLoading = true;
    this.isSaving = false;
    this.showForm = false;
    this.form = this.createEmptyForm();
  }
  ngOnInit() {
    this.loadProcedures();
  }
  get filteredProcedures() {
    const term = this.searchTerm.trim().toLowerCase();
    if (!term) return this.procedures;
    return this.procedures.filter(procedure => procedure.title.toLowerCase().includes(term) || procedure.category.toLowerCase().includes(term) || procedure.assignedUnit.toLowerCase().includes(term));
  }
  loadProcedures() {
    this.isLoading = true;
    this.procedureManagementService.list().subscribe({
      next: procedures => {
        this.procedures = procedures;
        this.isLoading = false;
      },
      error: () => {
        this.procedures = [];
        this.isLoading = false;
      }
    });
  }
  openCreate() {
    this.selectedProcedure = null;
